"""
飞书 Bot 自部署脚本

通过飞书发送给 Bot，让 Bot 执行此脚本完成自我更新。
在飞书中发送以下消息给 Bot：

    请运行以下脚本更新你的代码，然后重启服务：
    [将此文件的完整内容粘贴在此]

用法: python3 self_deploy.py [--restart]
"""

import os
import sys
import base64
import subprocess

# 服务器上 feishu-bot 的根目录
BOT_DIR = "/workspace/claude-history/feishu-bot"

# ========== 文件内容（base64 编码）==========

# app/tools/feishu_tools.py (23693 字节)
FEISHU_TOOLS_PY_B64 = """"""

# app/engine/tool_definitions.py (13705 字节)
TOOL_DEFINITIONS_PY_B64 = """"""

# app/tools/executor.py (5225 字节)
EXECUTOR_PY_B64 = """"""

# app/engine/system_prompt.py (2651 字节)
SYSTEM_PROMPT_PY_B64 = """"""

# ========== 文件列表 ==========
FILES = [
    ("app/tools/feishu_tools.py", FEISHU_TOOLS_PY_B64),
    ("app/engine/tool_definitions.py", TOOL_DEFINITIONS_PY_B64),
    ("app/tools/executor.py", EXECUTOR_PY_B64),
    ("app/engine/system_prompt.py", SYSTEM_PROMPT_PY_B64),
]


def write_files():
    """将所有文件写入服务器对应位置。"""
    for rel_path, b64_content in FILES:
        decoded = base64.b64decode(b64_content).decode("utf-8")
        full_path = os.path.join(BOT_DIR, rel_path)
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        with open(full_path, "w", encoding="utf-8") as f:
            f.write(decoded)
        print(f"\u2713 \u5df2\u5199\u5165: {rel_path} ({len(decoded)} \u5b57\u7b26)")
    print("\n\u6240\u6709\u6587\u4ef6\u5199\u5165\u5b8c\u6210\uff01")


def restart_service():
    """\u91cd\u542f feishu-bot \u670d\u52a1\u3002"""
    import subprocess
    result = subprocess.run(
        ["sudo", "systemctl", "restart", "feishu-bot"],
        capture_output=True, text=True, timeout=30
    )
    if result.returncode == 0:
        print("\u2713 \u670d\u52a1\u5df2\u91cd\u542f")
        status = subprocess.run(
            ["sudo", "systemctl", "status", "feishu-bot", "--no-pager"],
            capture_output=True, text=True, timeout=10
        )
        print(status.stdout[:500])
    else:
        print(f"\u2717 \u91cd\u542f\u5931\u8d25: {result.stderr}")


if __name__ == "__main__":
    print("=" * 50)
    print("\u98de\u4e66 Bot \u81ea\u90e8\u7f72\u811a\u672c")
    print("=" * 50)

    if not os.path.exists(BOT_DIR):
        print(f"\u2717 \u9519\u8bef: \u672a\u627e\u5230 {BOT_DIR}")
        print("\u8bf7\u786e\u8ba4\u4f60\u5728\u6b63\u786e\u7684\u670d\u52a1\u5668\u4e0a\u8fd0\u884c\u6b64\u811a\u672c")
        sys.exit(1)

    write_files()

    if "--restart" in sys.argv:
        restart_service()
    else:
        print()
        print("\u6587\u4ef6\u5df2\u5199\u5165\u3002\u5982\u9700\u91cd\u542f\u670d\u52a1\uff0c\u8bf7\u8fd0\u884c:")
        print(f"  python3 {sys.argv[0]} --restart")
